# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_basic.test_call","kind":"function","src_hash":"1c6071a8c39a8566","in":{"base":"Any"},"out":{"base":"Any","pred":"sin(x).rcall(1) == sin(x) and (1 + sin(x)).rcall(1) == 1 + sin(x) and (l + x).rcall(y) == 2 * y + x and (x ** l).rcall(2) == x ** 4 and (Q.real & Q.positive).rcall(x) == Q.real(x) & Q.positive(x)"},"spec":{"lhs":"test_call()","rhs":"test_call produces the expected output","over":{"base":"Any"},"name":"test_call_correct"},"guarantee":"test_call produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_basic.test_call_correct","statement":"Path(test_call(x), test_call produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"ac9d9910a39178e8"}
def test_call():
    x, y = symbols('x y')
    # See the long history of this in issues 5026 and 5105.

    raises(TypeError, lambda: sin(x)({ x : 1, sin(x) : 2}))
    raises(TypeError, lambda: sin(x)(1))

    # No effect as there are no callables
    assert sin(x).rcall(1) == sin(x)
    assert (1 + sin(x)).rcall(1) == 1 + sin(x)

    # Effect in the presence of callables
    l = Lambda(x, 2*x)
    assert (l + x).rcall(y) == 2*y + x
    assert (x**l).rcall(2) == x**4
    # TODO UndefinedFunction does not subclass Expr
    #f = Function('f')
    #assert (2*f)(x) == 2*f(x)

    assert (Q.real & Q.positive).rcall(x) == Q.real(x) & Q.positive(x)


