# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_basic.test_rewrite","kind":"function","src_hash":"c6f2a32e4cfa331c","in":{"base":"Any"},"out":{"base":"Any","pred":"f1.rewrite(cos, exp) == exp(I * x) / 2 + sin(x) + exp(-I * x) / 2 and f1.rewrite([cos], sin) == sin(x) + sin(x + pi / 2, evaluate=False) and f2.rewrite(sin, exp) == -I * (exp(I * x) - exp(-I * x)) / 2 + cos(y) / gamma(z) and f1.rewrite() == f1"},"spec":{"lhs":"test_rewrite()","rhs":"test_rewrite produces the expected output","over":{"base":"Any"},"name":"test_rewrite_correct"},"guarantee":"test_rewrite produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_basic.test_rewrite_correct","statement":"Path(test_rewrite(x), test_rewrite produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"d1dab4f8eeede1c4"}
def test_rewrite():
    x, y, z = symbols('x y z')
    a, b = symbols('a b')
    f1 = sin(x) + cos(x)
    assert f1.rewrite(cos,exp) == exp(I*x)/2 + sin(x) + exp(-I*x)/2
    assert f1.rewrite([cos],sin) == sin(x) + sin(x + pi/2, evaluate=False)
    f2 = sin(x) + cos(y)/gamma(z)
    assert f2.rewrite(sin,exp) == -I*(exp(I*x) - exp(-I*x))/2 + cos(y)/gamma(z)

    assert f1.rewrite() == f1

