# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_basic.test_as_dummy","kind":"function","src_hash":"856d998c8d8325b4","in":{"base":"Any"},"out":{"base":"Any","pred":"Lambda(x, x + 1).as_dummy() == Lambda(_0, _0 + 1) and Lambda(x, x + _0).as_dummy() == Lambda(_1, _0 + _1) and once == ans and twice == ans and Dummy().as_dummy().is_commutative and Dummy(commutative=False).as_dummy().is_commutative is False and D != d and D.func == Dummy and (D.is_real is None)"},"spec":{"lhs":"test_as_dummy()","rhs":"test_as_dummy produces the expected output","over":{"base":"Any"},"name":"test_as_dummy_correct"},"guarantee":"test_as_dummy produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_basic.test_as_dummy_correct","statement":"Path(test_as_dummy(x), test_as_dummy produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"5cf01873b6da64e3"}
def test_as_dummy():
    u, v, x, y, z, _0, _1 = symbols('u v x y z _0 _1')
    assert Lambda(x, x + 1).as_dummy() == Lambda(_0, _0 + 1)
    assert Lambda(x, x + _0).as_dummy() == Lambda(_1, _0 + _1)
    eq = (1 + Sum(x, (x, 1, x)))
    ans = 1 + Sum(_0, (_0, 1, x))
    once = eq.as_dummy()
    assert once == ans
    twice = once.as_dummy()
    assert twice == ans
    assert Integral(x + _0, (x, x + 1), (_0, 1, 2)
        ).as_dummy() == Integral(_0 + _1, (_0, x + 1), (_1, 1, 2))
    for T in (Symbol, Dummy):
        d = T('x', real=True)
        D = d.as_dummy()
        assert D != d and D.func == Dummy and D.is_real is None
    assert Dummy().as_dummy().is_commutative
    assert Dummy(commutative=False).as_dummy().is_commutative is False


